const raw = $input.first().json;
const html = typeof raw === 'string' ? raw : (raw.data || raw.body || JSON.stringify(raw));

// Extract posts from Telegram public preview HTML
// Each post is in <div class="tgme_widget_message_text js-message_text" ... >TEXT</div>
const postRegex = /<div[^>]*class="[^"]*tgme_widget_message_text[^"]*"[^>]*>([\s\S]*?)<\/div>/g;
const posts = [];
let m;
while ((m = postRegex.exec(html)) !== null && posts.length < 15) {
  let txt = m[1]
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<a[^>]*>([\s\S]*?)<\/a>/g, '$1')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '\"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ')
    .trim();
  if (txt.length > 40) posts.push(txt.slice(0, 600));
}

// Fallback if no posts found
let styleRef = '';
if (posts.length) {
  styleRef = posts.slice(0, 10).map((p,i) => '--- Пример ' + (i+1) + ' ---\n' + p).join('\n\n');
} else {
  styleRef = '(Канал пока без постов. Пиши тёплым городским тоном, как будто рассказываешь соседу хорошую новость о родном городе. Без пафоса, без казённого языка. Короткие предложения, конкретика, уважение к читателю.)';
}

return [{ json: { styleRef, sampleCount: posts.length } }];

const res = $input.first().json;
const content = res.content || [];

// Last text block contains final answer
let jsonText = '';
for (const c of content.slice().reverse()) {
  if (c.type === 'text' && c.text) {
    jsonText = c.text;
    break;
  }
}

if (!jsonText) return [];

jsonText = jsonText.replace(/```json\s*/g, '').replace(/```\s*$/g, '').trim();
// Extract first JSON object if there's surrounding text
const jm = jsonText.match(/\{[\s\S]*\}/);
if (jm) jsonText = jm[0];

let parsed;
try { parsed = JSON.parse(jsonText); } catch(e) { return []; }

const posts = parsed.posts || [];
const searchedCount = parsed.searched_count || 0;
if (!posts.length) return [];

function normalize(s) {
  return (s || '').toLowerCase()
    .replace(/[^a-zа-я0-9\s]/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 50);
}

const store = $getWorkflowStaticData('global');
if (!store.sentChelPosts) store.sentChelPosts = [];
const sentSet = new Set(store.sentChelPosts);

const styleRef = $('Prep Research Body').first().json.styleRef || '';
const seenInRun = new Set();
const fresh = [];
for (const p of posts) {
  if (!p.headline) continue;
  const key = normalize(p.headline);
  if (!key || key.length < 5) continue;
  if (sentSet.has(key) || seenInRun.has(key)) continue;
  seenInRun.add(key);
  fresh.push({ ...p, styleRef, searchedCount });
  store.sentChelPosts.push(key);
}

if (store.sentChelPosts.length > 500) store.sentChelPosts = store.sentChelPosts.slice(-500);

return fresh.map(p => ({ json: p }));

const res = $input.first().json;
let post = '';
if (res.content && Array.isArray(res.content)) {
  const textBlock = res.content.find(c => c.type === 'text');
  post = textBlock?.text?.trim() || '';
}
post = post.replace(/@che_v_che\s*$/i, '').trim();
post += '\n\n@che_v_che';
const id = 'chel_' + Date.now() + '_' + Math.random().toString(36).slice(2,7);
return [{ json: { post, id } }];
